import { createContext, useState, useEffect } from "react";
import { getMe } from "../api/auth";
import { saveToken, getToken, saveUser, getUser, clearAuthData } from "../utils/localStorage";
import { useNavigate } from "react-router-dom";

// ============================================================================
// CONSTANTS
// ============================================================================

const ROUTES = {
  STUDENT_DASHBOARD: "/dashboard",
  TEACHER_DASHBOARD: "/teacher/dashboard",
  LOGIN: "/login",
};

const ROLES = {
  STUDENT: "student",
  TEACHER: "teacher",
};

// ============================================================================
// UTILITY FUNCTIONS
// ============================================================================

/**
 * Détermine le rôle de l'utilisateur à partir des données utilisateur
 * @param {object} userData - Données utilisateur
 * @returns {string} - 'student' ou 'teacher'
 */
const getUserRole = (userData) => {
  if (!userData) {
    console.warn("⚠️ Aucun userData fourni, utilisation du rôle par défaut (student)");
    return ROLES.STUDENT;
  }

  // Vérifier si le rôle est peuplé (objet avec name)
  if (userData.role && typeof userData.role === "object") {
    const roleName = userData.role.name || userData.role.type;

    if (roleName) {
      const normalizedRole = roleName.toLowerCase();

      // Détection des rôles teacher
      if (
        normalizedRole.includes("teacher") ||
        normalizedRole.includes("professor") ||
        normalizedRole.includes("enseignant") ||
        normalizedRole.includes("formateur")
      ) {
        return ROLES.TEACHER;
      }

      // Détection des rôles student
      if (
        normalizedRole.includes("student") ||
        normalizedRole.includes("étudiant") ||
        normalizedRole.includes("eleve")
      ) {
        return ROLES.STUDENT;
      }

      console.warn(`⚠️ Rôle non reconnu: "${roleName}", utilisation par défaut (student)`);
      return ROLES.STUDENT;
    }
  }

  // Si le rôle n'est pas peuplé (ID numérique)
  if (userData.role && typeof userData.role === "number") {
    console.error(
      "❌ Rôle non peuplé! Le rôle est un ID (nombre), pas un objet. Il faut utiliser getMe() pour obtenir le rôle peuplé."
    );
  }

  // Fallback basé sur des champs métier
  if (userData.isTeacher) {
    return ROLES.TEACHER;
  }

  // Par défaut, retourner student
  console.warn("⚠️ Rôle non détecté, utilisation par défaut (student)");
  return ROLES.STUDENT;
};

/**
 * Redirige l'utilisateur vers le dashboard approprié selon son rôle
 * @param {string} role - Rôle de l'utilisateur ('student' ou 'teacher')
 * @param {Function} navigate - Fonction de navigation de react-router-dom
 */
const redirectToDashboard = (role, navigate) => {
  if (role === ROLES.STUDENT) {
    console.log("👨‍🎓 Redirection vers dashboard étudiant");
    navigate(ROUTES.STUDENT_DASHBOARD);
  } else {
    console.log("👨‍🏫 Redirection vers dashboard professeur");
    navigate(ROUTES.TEACHER_DASHBOARD);
  }
};

// ============================================================================
// CONTEXT
// ============================================================================

export const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [isLoading, setIsLoading] = useState(true);
  const navigate = useNavigate();

  // Fonction pour déterminer le rôle de l'utilisateur
  const getUserRole = (userData) => {
    if (!userData) {
      console.warn('⚠️ Aucun userData fourni, utilisation du rôle par défaut (student)');
      return 'student';
    }
    
    console.log('🔍 Structure userData reçue:', userData);
    console.log('🔍 Type de userData.role:', typeof userData.role, userData.role);
    
    // Vérifier si le rôle est peuplé (devrait l'être grâce à populate=role)
    if (userData.role && typeof userData.role === 'object') {
      const roleName = userData.role.name || userData.role.type;
      console.log('🎭 Rôle détecté:', roleName);
      
      if (roleName) {
        const normalizedRole = roleName.toLowerCase();
        
        // Mapping des rôles possibles
        if (normalizedRole.includes('teacher') || 
            normalizedRole.includes('professor') || 
            normalizedRole.includes('enseignant') ||
            normalizedRole.includes('formateur')) {
          return 'teacher';
        } else if (normalizedRole.includes('student') || 
                   normalizedRole.includes('étudiant') || 
                   normalizedRole.includes('eleve')) {
          return 'student';
        }
        
        console.warn(`⚠️ Rôle non reconnu: "${roleName}", utilisation par défaut (student)`);
        return 'student';
      }
    }
    
    // Si le rôle n'est pas peuplé (ne devrait pas arriver avec populate=role)
    if (userData.role && typeof userData.role === 'number') {
      console.error('❌ Rôle non peuplé! Le rôle est un ID (nombre), pas un objet. Il faut utiliser getMe() pour obtenir le rôle peuplé.');
      // Ne pas refaire d'appel API pour éviter les boucles infinies
    }
    
    // Fallback basé sur des champs métier (optionnel)
    if (userData.isTeacher) {
      return 'teacher';
    }
    
    console.warn('⚠️ Rôle non détecté, utilisation par défaut (student)');
    return 'student';
  };

  // Vérifier si un token existe au chargement de l'application
  useEffect(() => {
    const checkAuth = async () => {
      const token = getToken();
      const savedUser = getUser();

      if (token) {
        try {
          // Tenter de récupérer les données utilisateur depuis le serveur
          const userData = await getMe();
          setUser(userData);
          
          // Rediriger selon le rôle au chargement de l'app
          const role = getUserRole(userData);
          console.log('🧭 Redirection selon rôle détecté:', role);
          console.log('🧭 Données rôle brutes:', userData.role);
          
          if (role === 'teacher') {
            console.log('👨‍🏫 Redirection vers dashboard prof');
            navigate("/teacher/dashboard");
          } else {
            console.log('👨‍🎓 Redirection vers dashboard étudiant');
            navigate("/dashboard");
          }
          
        } catch (error) {
          console.warn("Token invalide ou expiré, déconnexion...");
          clearAuthData();
          setUser(null);
        }
      } else if (savedUser) {
        clearAuthData();
      }

      setIsLoading(false);
    };

    checkAuth();
  }, [navigate]);

  const loginUser = async (data) => {
    if (!data || !data.jwt || !data.user) {
      console.error("Données d'authentification invalides");
      return;
    }

    console.log('🔐 Données reçues de /auth/local:', data);
    console.log('🔐 Structure data.user:', data.user);
    console.log('🔐 Type de data.user.role:', typeof data.user.role, data.user.role);

    // Sauvegarder le token d'abord
    saveToken(data.jwt);
    saveUser(data.user);
    
    try {
      // PROBLÈME IDENTIFIÉ : La réponse de /auth/local ne contient PAS le rôle peuplé
      // Elle retourne user.role comme un ID (nombre), pas comme un objet avec name
      // Il faut appeler getMe() pour obtenir les données complètes avec le rôle peuplé
      console.log('📡 Récupération des données utilisateur complètes avec getMe()...');
      const userData = await getMe();
      console.log('✅ Données utilisateur complètes récupérées:', userData);
      setUser(userData);
      
      // Déterminer le rôle et rediriger
      const role = getUserRole(userData);
      console.log('🔐 Connexion réussie, rôle détecté:', role);
      console.log('🔐 Données rôle complètes:', userData.role);
      
      if (role === 'teacher') {
        console.log('👨‍🏫 Redirection vers dashboard prof');
        navigate("/teacher/dashboard");
      } else {
        console.log('👨‍🎓 Redirection vers dashboard étudiant');
        navigate("/dashboard");
      }
    } catch (error) {
      console.error('❌ Erreur lors de la récupération des données utilisateur:', error);
      // En cas d'erreur, utiliser les données de base et rediriger vers dashboard par défaut
      console.warn('⚠️ Utilisation des données de base (rôle peut ne pas être détecté)');
      setUser(data.user);
      navigate("/dashboard");
    }
  };

  const logout = () => {
    console.log('🚪 Déconnexion');
    clearAuthData();
    setUser(null);
    navigate("/login");
  };

  return (
    <AuthContext.Provider value={{ user, loginUser, logout, isLoading }}>
      {children}
    </AuthContext.Provider>
  );
};
